const fs = require('fs');
const path = require('path');

const filePath = items[0].json.path;
const fileName = items[0].json.fileName;
const fileExt = path.extname(fileName).toLowerCase();

let textContent = '';

if (fileExt === '.txt') {
  // Simple text file
  textContent = fs.readFileSync(filePath, 'utf8');
} else if (fileExt === '.pdf') {
  // For PDF, we'll use a simple extraction
  // Note: In production, use pdf-parse library
  textContent = `[PDF content from ${fileName}]`;
  // TODO: Implement actual PDF parsing
} else if (fileExt === '.docx') {
  // For DOCX, would use mammoth library
  textContent = `[DOCX content from ${fileName}]`;
  // TODO: Implement actual DOCX parsing
} else if (fileExt === '.pptx') {
  // For PPTX, would use appropriate library
  textContent = `[PPTX content from ${fileName}]`;
  // TODO: Implement actual PPTX parsing
}

return [{
  json: {
    ...items[0].json,
    textContent: textContent,
    fileType: fileExt.replace('.', '')
  }
}];

// Prepare Claude API request for lecture notes
const textContent = items[0].json.textContent;
const fileName = items[0].json.fileName;

const prompt = `Based on this lecture content, please create:

1. A comprehensive summary (300-500 words) that captures the main points and key takeaways
2. 10 review questions with detailed answers to test understanding
3. 15 flashcards in the format "Q: [question] | A: [answer]"
4. Key concepts and their relationships (as a list)
5. Suggested related topics to explore

Lecture Content:
${textContent}

Please structure your response with clear headers for each section.`;

return [{
  json: {
    ...items[0].json,
    claudePrompt: prompt,
    contentType: 'lecture'
  }
}];

// Prepare Claude API request for assignments
const textContent = items[0].json.textContent;
const fileName = items[0].json.fileName;

const prompt = `Based on this assignment description, please create:

1. A clear breakdown of requirements (bulleted list)
2. A suggested approach/strategy to complete this assignment
3. Key concepts/topics to review before starting
4. A checklist of deliverables
5. Common pitfalls to avoid

Assignment Content:
${textContent}`;

return [{
  json: {
    ...items[0].json,
    claudePrompt: prompt,
    contentType: 'assignment'
  }
}];

// Parse Claude's response and structure it
const response = items[0].json;
const content = response.content[0].text;
const originalData = items[0].json;

// Simple parsing - in production, use more robust parsing
const sections = content.split('\n\n');

return [{
  json: {
    ...originalData,
    claudeResponse: content,
    parsedResponse: {
      summary: sections[0] || '',
      questions: sections[1] || '',
      flashcards: sections[2] || '',
      concepts: sections[3] || '',
      relatedTopics: sections[4] || ''
    }
  }
}];

// Format content for Obsidian markdown
const data = items[0].json;
const parsed = data.parsedResponse;
const now = new Date();

const markdown = `---
type: ${data.contentType}-notes
course: "${data.courseName || 'Unknown'}"
date: ${now.toISOString().split('T')[0]}
source: ${data.fileName}
tags: [${data.courseName || 'study'}, ${data.contentType}, ai-generated]
---

# ${data.fileName.replace(/\.[^/.]+$/, '')}

## 📝 Summary
${parsed.summary}

## ❓ Review Questions
${parsed.questions}

## 🎴 Flashcards
${parsed.flashcards}

## 🧠 Key Concepts
${parsed.concepts}

## 🔗 Related Topics
${parsed.relatedTopics}

## 📎 Original Material
![[${data.fileName}]]

---
*Generated on: ${now.toISOString()}*
*Powered by: Claude AI*
`;

return [{
  json: {
    ...data,
    markdownContent: markdown,
    noteName: data.fileName.replace(/\.[^/.]+$/, '') + '.md'
  }
}];
